async function revokeShareLink(token: string): Promise<void> {
  await kv.del(shareKey(token))
}

function cacheKey(date: string, country: string, city: string): string {
  return `events:${date}:${country}:${city}`.toLowerCase().replace(/\s+/g, "_")
}
